import React from "react";
import { useNavigate } from "react-router-dom";
import { useApp } from "../App";

export default function ProfilePage() {
  const { user } = useApp();
  const navigate = useNavigate();

  const total = user.wins + user.losses + user.draws;
  const winRate = total > 0 ? Math.round((user.wins / total) * 100) : 0;

  const ranks = [
    { threshold: 0,  name: "Новичок",  icon: "🥚" },
    { threshold: 5,  name: "Боец",     icon: "⚔️" },
    { threshold: 15, name: "Ветеран",  icon: "🛡️" },
    { threshold: 30, name: "Мастер",   icon: "👑" },
    { threshold: 60, name: "Легенда",  icon: "🔥" },
  ];
  const currentRankIdx = ranks.findLastIndex(r => user.wins >= r.threshold);
  const nextRank = ranks[currentRankIdx + 1];
  const progress = nextRank
    ? ((user.wins - ranks[currentRankIdx].threshold) / (nextRank.threshold - ranks[currentRankIdx].threshold)) * 100
    : 100;

  return (
    <div className="page animate-fade">
      {/* Avatar & Name */}
      <div style={{ textAlign: "center", marginBottom: 28 }}>
        <div style={{
          width: 80, height: 80, borderRadius: "50%",
          background: "linear-gradient(135deg, var(--accent), var(--accent2))",
          display: "flex", alignItems: "center", justifyContent: "center",
          fontSize: 32, margin: "0 auto 12px",
          boxShadow: "0 0 30px rgba(124,92,252,0.4)"
        }}>
          {user.first_name[0]?.toUpperCase()}
        </div>
        <div style={{ fontFamily: "Unbounded", fontSize: 20, fontWeight: 700, marginBottom: 4 }}>
          {user.first_name}
        </div>
        {user.username && (
          <div style={{ color: "var(--text2)", fontSize: 13 }}>@{user.username}</div>
        )}
        <div style={{ marginTop: 8 }}>
          <span style={{ fontSize: 24 }}>{user.rank.icon}</span>
          <span style={{ fontFamily: "Unbounded", fontSize: 14, marginLeft: 6, color: "var(--accent3)" }}>
            {user.rank.name}
          </span>
        </div>
      </div>

      {/* Coins */}
      <div className="card" style={{ textAlign: "center", marginBottom: 16 }}>
        <div style={{ color: "var(--text2)", fontSize: 12, marginBottom: 4 }}>БАЛАНС</div>
        <div style={{ fontFamily: "Unbounded", fontSize: 32, fontWeight: 900, color: "var(--gold)" }}>
          🪙 {user.coins}
        </div>
        <button className="btn btn-gold btn-sm" style={{ marginTop: 12 }}
          onClick={() => navigate("/topup")}
        >
          Пополнить
        </button>
      </div>

      {/* Stats */}
      <div style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: 10, marginBottom: 16 }}>
        {[
          { label: "Победы", value: user.wins, color: "var(--green)" },
          { label: "Ничьи", value: user.draws, color: "var(--gold)" },
          { label: "Поражения", value: user.losses, color: "var(--red)" },
        ].map(s => (
          <div key={s.label} className="card" style={{ textAlign: "center", padding: 16 }}>
            <div style={{ fontFamily: "Unbounded", fontSize: 24, fontWeight: 900, color: s.color }}>
              {s.value}
            </div>
            <div style={{ color: "var(--text2)", fontSize: 11, marginTop: 4 }}>{s.label}</div>
          </div>
        ))}
      </div>

      {/* Win rate */}
      <div className="card" style={{ marginBottom: 16 }}>
        <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 10 }}>
          <span style={{ color: "var(--text2)", fontSize: 13 }}>Процент побед</span>
          <span style={{ fontWeight: 700, color: "var(--accent2)" }}>{winRate}%</span>
        </div>
        <div style={{ height: 8, background: "var(--bg3)", borderRadius: 4, overflow: "hidden" }}>
          <div style={{
            width: `${winRate}%`, height: "100%",
            background: "linear-gradient(90deg, var(--accent), var(--accent2))",
            borderRadius: 4, transition: "width 1s ease"
          }} />
        </div>
      </div>

      {/* Rank progress */}
      {nextRank && (
        <div className="card" style={{ marginBottom: 16 }}>
          <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 10 }}>
            <span style={{ color: "var(--text2)", fontSize: 13 }}>До ранга {nextRank.icon} {nextRank.name}</span>
            <span style={{ fontWeight: 700, color: "var(--accent2)" }}>
              {user.wins}/{nextRank.threshold}
            </span>
          </div>
          <div style={{ height: 8, background: "var(--bg3)", borderRadius: 4, overflow: "hidden" }}>
            <div style={{
              width: `${progress}%`, height: "100%",
              background: "linear-gradient(90deg, var(--gold), #f97316)",
              borderRadius: 4, transition: "width 1s ease"
            }} />
          </div>
        </div>
      )}

      {/* All ranks */}
      <div className="card">
        <div style={{ fontWeight: 700, marginBottom: 12, fontSize: 13, color: "var(--text2)" }}>ВСЕ РАНГИ</div>
        {ranks.map((r, i) => (
          <div key={i} style={{
            display: "flex", alignItems: "center", gap: 12,
            padding: "8px 0", borderBottom: i < ranks.length - 1 ? "1px solid var(--border)" : "none",
            opacity: user.wins >= r.threshold ? 1 : 0.4
          }}>
            <span style={{ fontSize: 20 }}>{r.icon}</span>
            <span style={{ flex: 1, fontWeight: 600, fontSize: 14 }}>{r.name}</span>
            <span style={{ color: "var(--text2)", fontSize: 12 }}>{r.threshold}+ побед</span>
            {user.wins >= r.threshold && (
              <span style={{ color: "var(--green)", fontSize: 12 }}>✓</span>
            )}
          </div>
        ))}
      </div>
    </div>
  );
}
